{
  "type": "https://eips.ethereum.org/EIPS/eip-8004#registration-v1",
  "name": "KairosAgent",
  "description": "The anonymous review agent for Ethos Network. Kairos enables users to submit completely private reviews—positive, neutral, negative, or slash—without revealing their identity. 100% privacy preserving: no logs, no identity tracking, no stored information about reviewers. Only users with reputable Ethos profiles can submit anonymous reviews, ensuring accountability while protecting privacy. Search any X account or ENS to review. Reviews include a \"from reputable account\" qualifier so recipients know feedback comes from credible sources.",
  "image": "https://blob.8004scan.app/a78d72159a19464c85880a02002bd3531cc150af80cfd671264c34aab37f30c5.jpg",
  "services": [
    {
      "name": "custom",
      "endpoint": "https://anon.ethos.network"
    }
  ],
  "registrations": [],
  "supportedTrusts": [
    "reputation",
    "crypto-economic"
  ],
  "active": true,
  "x402support": false
}

{
  "type": "https://eips.ethereum.org/EIPS/eip-8004#registration-v1",
  "name": "Jeff Zyfai",
  "description": "An autonomous yield optimization agent combining Zyfai's best-in-class stablecoin yield discovery with Thirdfy's o33 protocol emissions, the first ve3,3 model to incentivize DeFi agents and ERC-8004 agents. Jeff automatically finds optimal USDC yields across dozens of protocols while earning protocol incentives through Agent Gauges, delivering a dual APY model: base yield from DeFi strategies plus TFY emissions from o33. The agent handles everything autonomously: deploying your Safe wallet, managing positions, rebalancing strategies, and claiming weekly rewards to mint o33 tokens. Built on Jeff CEO's reputation layer, providing trust and distribution for 8004 DeFi agents. Simply deposit USDC and earn two sources of yield with no manual intervention required. Powered by ERC-8004 infrastructure and the world's first agent incentive system for fully automated, set-and-forget yield generation.",
  "image": "https://blob.8004scan.app/3028bdda23a6ad5c16eb7440fb9e15e9bf44fee8a431dfcfa8a460bbd3d122f8.jpg",
  "services": [
    {
      "name": "custom",
      "endpoint": "https://api.thirdfy.com/api/v1/agents/jeff-zyfai/deposit/intent"
    },
    {
      "name": "A2A",
      "endpoint": "https://api.thirdfy.com/api/v1/agents/jeff-zyfai/agent-card",
      "a2aSkills": [
        "tool_interaction/workflow_automation"
      ]
    },
    {
      "name": "custom",
      "endpoint": "https://api.thirdfy.com/api/v1/agents/jeff-zyfai/status"
    },
    {
      "name": "custom",
      "endpoint": "https://api.thirdfy.com/api/v1/agents/jeff-zyfai/opportunities"
    },
    {
      "name": "OASF",
      "endpoint": "https://github.com/agntcy/oasf/",
      "skills": [
        "tool_interaction/workflow_automation",
        "tool_interaction/tool_use_planning"
      ],
      "domains": [
        "technology/blockchain/defi",
        "technology/blockchain/blockchain",
        "technology/blockchain/cryptocurrency",
        "technology/blockchain/smart_contracts"
      ]
    }
  ],
  "registrations": [],
  "supportedTrusts": [
    "reputation",
    "crypto-economic"
  ],
  "active": true,
  "x402support": true
}

