{
  "type": "https://eips.ethereum.org/EIPS/eip-8004#registration-v1",
  "name": "Early Token Red Flag Detector",
  "description": "Early Token Red Flag Detector is an AI-powered agent that helps traders identify potential risks in newly launched tokens before making a buy decision.\n\nThe agent analyzes early-stage red flags such as:\n- Ownership concentration and hidden control risks\n- Liquidity availability and lock status\n- Minting functions, supply manipulation, and abnormal token behavior\n- Common contract-level risk patterns seen in failed or malicious launches\n\nThis agent does not provide price predictions or financial advice. Its purpose is to surface early risk signals so users can make more informed decisions in fast-moving markets.\n",
  "image": "https://blob.8004scan.app/54faa1d17b00c689e1253cf286b6e084d752011e25a1833291c5ab96cb6c1451.jpg",
  "services": [
    {
      "name": "OASF",
      "endpoint": "https://github.com/agntcy/oasf/",
      "skills": [
        "natural_language_processing/analytical_reasoning/problem_solving"
      ],
      "domains": [
        "trust_and_safety/risk_management",
        "trust_and_safety/trust_and_safety"
      ]
    }
  ],
  "registrations": [],
  "supportedTrusts": [
    "reputation"
  ],
  "active": true,
  "x402support": false
}

